/* --- ୨୧BalletDream --- */
/* --- 作者@Rose_are_roses --- */
/* --- 仅免费发布于本人自己的小群，偶尔发布于Discord堆堆demo/尾巴镇社区，严禁除以上渠道外的任何获取方式，严禁二传、任何商业行为，仅限社区内二改。 --- */


/* =============== 字体 =============== */
@import url("https://fontsapi.zeoseven.com/7/main/result.css");

body, .text_pole, select, .text_input, textarea, .menu_button, button {
    font-family: var(--font-main) !important;
    font-weight: normal !important;
}
.fa, .fas, .far, .fab, .fa-solid {
    font-family: "Font Awesome 6 Free" !important;
}


/* =============== 全局设置 =============== */
:root {
    --ballet-pink: #F5E3E8 !important;
    --ballet-pink-light: #FFFAFB !important;
    --dusty-rose: #E5C5CB !important;
    --shen-rose: #C88F9A !important;
    --shen-ballet: #EECFD7 !important;
    --chaoqian-lan: #F5FBFF !important;
    --qian-lan: #EDF7FF !important;
    --text-blue: #8FB0CA !important;
    --text-color: #6E5C64 !important;
    --font-main: "Zhuque Fangsong (technical preview)", serif; 
}

* {
    text-shadow: none !important;
    box-shadow: none !important;
    filter: none !important;
}


/* ============= 弹窗、侧边栏、菜单 ============= */
.drawer-content,
#table_drawer_content {
    background-color: rgb(255, 248, 249) !important;
    border: 1px solid rgba(229, 197, 203, 0.4) !important;
    color: var(--text-color) !important; 
}
.drawer-content {
    border-radius: 0;
}

/* 菜单背景填满屏幕，感谢NAKARI老师 */
.drawer-content.openDrawer {
        max-height: calc(100dvh - var(--topBarBlockSize));
}
#left-nav-panel,
#right-nav-panel {
    height: 100dvh;
    max-height: 100dvh;
}
@media (max-width: 600px) {
    #right-nav-panel {
        max-height: calc(100dvh - var(--topBarBlockSize));
    }
}


/* ============= 正则/脚本 ============= */
.regex-script-label.flex-container,
.script-item {
    padding: 0 4px 0 8px;
     height: auto !important;
    background-color: var(--ballet-pink-light) !important; 
    border: 1px solid rgba(229, 197, 203, 0.5) !important;
    border-radius: 6px !important;
    margin-left: 5px !important;
}
.regex-script-label .regex_script_name,
.script-item span {
    white-space: normal !important;
    text-overflow: clip !important;
    overflow: visible !important;
    line-height: 1.5 !important;  
}


/* =============== 预设页 =============== */
/* 预设底板 */
#completion_prompt_manager, 
#completion_prompt_manager_list {
    background: transparent !important;
    background-color: transparent !important;
    border: none !important;
}

/* 预设条目 */
#completion_prompt_manager .completion_prompt_manager_prompt {
    background-color: var(--ballet-pink-light) !important; 
    border: 1px solid rgba(229, 197, 203, 0.5) !important;
    border-radius: 8px !important;
    padding: 7px 10px !important;
    margin-bottom: 6px !important;
    transform: translateZ(0); 
}
/* 悬停效果 */
#completion_prompt_manager .completion_prompt_manager_prompt:hover {
    background-color: #fff !important; 
    border-color: var(--dusty-rose) !important;
    transform: translateY(-1px);
}

/* 提示词未启用时的文字颜色，感谢serein老师的分享 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name,
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt_disabled .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
color: var(--text-blue);
}
/* 提示词启用时文字颜色 */
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled) .completion_prompt_manager_prompt_name,
#completion_prompt_manager #completion_prompt_manager_list .completion_prompt_manager_prompt:not(.completion_prompt_manager_prompt_disabled) .completion_prompt_manager_prompt_name .prompt-manager-inspect-action {
color: var(--shen-rose);
}

/* 提示词标题 */
.completion_prompt_manager_header {
  color: var(--text-color) !important;
}

/* 开关按钮颜色 */
.completion_prompt_manager_prompt .fa-toggle-on,
.completion_prompt_manager_prompt .fa-toggle-off {
    color: var(--shen-rose) !important;
}
/* 小铅笔按钮颜色 */
.completion_prompt_manager_prompt .fa-pencil,
.completion_prompt_manager_prompt .fa-edit {
    color: var(--shen-rose) !important;
}


/* ================== 表单控件 ================== */
h4,
h4.standoutHeader,
.inline-drawer-header.standoutHeader,
.inline-drawer-toggle.inline-drawer-header,
.extension_container > .inline-drawer > .inline-drawer-toggle.inline-drawer-header,
#kobold_api-presets .title_restorable,
#novel_api-presets .title_restorable,
#openai_api-presets .title_restorable,
#textgenerationwebui_api-presets .title_restorable {
    background: #fffdfd !important;
    border: 1px solid var(--ballet-pink) !important;
    border-radius: 10px !important;
    padding: 5px 10px !important;
    margin-top: 6px !important;
    margin-bottom: 6px !important;
    display: flex;
    align-items: center;
    box-shadow: 0 1px 3px rgba(230, 200, 205, 0.25) !important;
}

/* 下拉框 */
.select2-container--default .select2-selection--single,
.text_pole, select, .text_input, textarea { 
    background: linear-gradient(180deg, #fff, #FFF9FA) !important; 
    border: 1px solid var(--ballet-pink) !important; 
    padding: 4px 8px !important;
    border-radius: 8px !important;
    box-shadow: inset 0 1px 3px rgba(230, 200, 205, 0.15);
  margin: 1px 0 !important;
}


/* ============= 世界书下拉选择框 ============= */
/*  外框 */
.select2-container--default .select2-selection--single,
.select2-container--default .select2-selection--multiple {
    background: linear-gradient(180deg, #FFFFFF 0%, var(--ballet-pink-light) 100%) !important; 
    border: 1px solid var(--dusty-rose) !important; 
    border-radius: 12px !important; 
    color: var(--text-color) !important;
    display: flex !important;
    align-items: center !important;
    opacity: 1 !important;
}
.select2-container--default .select2-selection--single .select2-selection__rendered,
.select2-container--default .select2-selection--multiple .select2-selection__rendered {
    color: var(--text-color) !important;
}
/* 选中小标签 */
.select2-container--default .select2-selection--multiple .select2-selection__choice {
    background-color: #FDF7F8 !important; 
    border: 1px solid var(--dusty-rose) !important;
    border-radius: 6px !important;
    color: #666666 !important;
    padding: 0 4px !important;
    display: inline-flex !important;
    align-items: center !important;
    font-weight: normal !important;
    opacity: 1 !important;
}
/*  "x" 删除按钮 */
.select2-container--default .select2-selection--multiple .select2-selection__choice__remove {
    color: var(--dusty-rose) !important;
    background-color: transparent !important; 
    opacity: 1 !important;
}
.select2-container--default .select2-selection--multiple .select2-selection__choice__remove:hover {
    background-color: var(--dusty-rose) !important;
    color: #FFF !important;
}
.select2-container--default 
.select2-selection--multiple 
.select2-search--inline {
    display: none !important;
}

/* 选项列表 */
select option {
    background: #fffdfd !important; 
    color: var(--text-color) !important; 
}

/* API响应 */
.drawer-content:has(#main_api) h4,
.drawer-content:has(#main_api) .standoutHeader,
.drawer-content:has(#main_api) .inline-drawer-header {
    background: none !important;
    color: var(--text-color) !important;
    border: none !important;
    border-radius: 0 !important;
    margin-top: 6px !important;
    margin-bottom: -3px !important;
    padding: 5px 0 !important; 
    box-shadow: none !important;
    font-weight: bold !important;
}
.options-content {
  font-family: var(--font-main) !important;
}


/* =============== 复选框 =============== */
input[type="checkbox"] {
  -webkit-appearance: none;
  border-radius: 4px;
  background-color: #fffdfd;;
  border: 0.8px solid var(--ballet-pink-light);
  cursor: pointer;
  position: relative;
}
input[type="checkbox"]:checked {
  background-color: #E2F0FA;
  border-color: var(--ballet-pink-light);
}


/* ============= 滑块 轨道 数字输入框 ============= */
input[type="range"] {
    -webkit-appearance: none !important;
    height: 0.5px !important;
    margin-bottom: 0px !important;
    appearance: none;
    background: transparent;
    filter: none !important;
    width: 100%;
    margin: 10px 0;
}
/* 轨道样式 */
input[type="range"]::-webkit-slider-runnable-track {
    height: 3.5px;
    border-radius: 5px;
    border: none;
    background: linear-gradient(90deg, var(--chaoqian-lan), var(--qian-lan));
    box-shadow: inset 0 0 4px rgba(188, 212, 231, 0.48);
}
/* 滑块样式 */
input[type="range"]::-webkit-slider-thumb {
    -webkit-appearance: none;
    appearance: none;
    box-shadow: none !important;
    width: 55px;
    height: 55px;
    background: url('https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMkptpPCY8Gup0J2AYInZCa9dXy5vcQgACwSAAAlAH4FX2k8TW1-a1XDYE.png') no-repeat center / contain;
    border: none;
    border-radius: 50%;
    margin-top: -22px;
    z-index: 3;
    opacity: 0.889;
}
/* 数字输入框 */
input[type="number"] {
    background-color: #FFFDFE !important;
    border: 1px solid var(--ballet-pink) !important;
    color: var(--text-color) !important;
    border-radius: 8px !important;
    padding: 4px 12px !important;
}


/* =============== 滚动条 =============== */
body ::-webkit-scrollbar,
*::-webkit-scrollbar {
    width: var(--scrollbar-width) !important;
    height: var(--scrollbar-width) !important; 
    background: transparent !important; 
}
body ::-webkit-scrollbar-thumb,
*::-webkit-scrollbar-thumb {
    background: linear-gradient(135deg, var(--ballet-pink-light) 0%, var(--ballet-pink) 100%) !important;
    border-radius: var(--scrollbar-radius) !important;
    border: 1.5px solid #FFF !important; 
    box-shadow: 
        inset 1px 1px 2px rgba(255, 255, 255, 0.35), 
        0 2px 4px rgba(229, 197, 203, 0.3) !important;
    min-height: 20px !important;
}
body ::-webkit-scrollbar-thumb:hover,
*::-webkit-scrollbar-thumb:hover {
    background: linear-gradient(135deg, var(--dusty-rose) 0%, var(--shen-ballet) 100%) !important;
    border: 1.5px solid #FFF !important; 
    box-shadow: 
        inset 1px 1px 3px rgba(255, 255, 255, 1), 
        0 0 8px var(--ballet-pink) !important; 
}
body ::-webkit-scrollbar-thumb:active,
*::-webkit-scrollbar-thumb:active {
    background: var(--dusty-rose) !important; 
    border: 1px solid #FFF !important;
}
body ::-webkit-scrollbar-track,
*::-webkit-scrollbar-track {
    background: transparent !important;
    border-radius: var(--scrollbar-radius) !important;
    margin: 3px !important;
}
body ::-webkit-scrollbar-button,
*::-webkit-scrollbar-button,
body ::-webkit-scrollbar-corner,
*::-webkit-scrollbar-corner {
    display: none !important;
    width: 0 !important;
    height: 0 !important;
    background: transparent !important;
}
#HotSwapWrapper > div::-webkit-scrollbar {
    height: 3px !important; 
}
#HotSwapWrapper > div::-webkit-scrollbar-thumb {
    background: var(--ballet-pink-light) !important;
    border: none !important;
    box-shadow: none !important;
}
/* Firefox 适配 */
* {
    scrollbar-width: thin !important; 
    scrollbar-color: var(--ballet-pink) transparent !important;
}
/* 如果想要完全隐藏滚动条，复制粘贴下面代码替换上面的滚动条部分所有代码 */
/* ::-webkit-scrollbar {
display: none;
} */




/* =============== 收藏栏 =============== */
/* 收藏角色滚动 */
#HotSwapWrapper {
overflow-x: auto; 
}
#HotSwapWrapper::-webkit-scrollbar {
display: none;
}
.hotswap.avatars_inline {
min-width: max-content; 
}
.hotswap.avatars_inline > .avatar.inline_avatar {
display: inline-block;
}
#HotSwapWrapper * {
max-width: none;
}
/* 收藏角色名字 */
.character_select.is_fav .ch_name {
  color: var(--shen-rose) !important;
}


/* =============== 通知吐司 =============== */
#toast-container, .toast {
    overflow: visible !important; 
}
/* 默认样式 */
#toast-container > .toast {
    background-image: none !important;
    background-color: #FCFEFF !important;
    border: 1.5px solid var(--ballet-pink) !important;
    border-radius: 10px !important;
    padding: 10px 12px 10px 40px; /* 上右下左 */
    min-height: 30px;
    max-width: 250px;
    box-shadow: 0 5px 6px rgba(110, 92, 100, 0.25) !important;
}

/* 错误 Error / 警告 Warning外观 */
#toast-container > .toast.toast-error,
#toast-container > .toast.toast-warning {
    background-color: #C0C0C0 !important;
    border-color: #A0A0A0 !important;
    background-image: none !important;
    box-shadow: 0 2px 5px rgba(0,0,0,0.2) !important;
}

/* 图标 */
.toast::before {
    content: '';
    position: absolute;
    left: -35px;
    top: 50%;
    transform: translateY(-50%);
    width: 70px;
    height: 70px;
    background-size: contain;
    background-repeat: no-repeat;
    background-position: center;
    background-image: url("https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEDat1o725BNVkiCK-X4b-kZxfptTY1XQACmhkAAvwJgVdz5kVxYrRF5DYE.png");
}

/* 消息文字样式 */
.toast-title {
    color: var(--text-color);
    font-size: 18px;
    font-weight: bold;
}
.toast-message {
    color: var(--text-color) !important;
    font-size: 12px !important;
}
/* 错误/警告文字 */
.toast-error .toast-title,
.toast-error .toast-message,
.toast-warning .toast-title,
.toast-warning .toast-message {
    color: #000000 !important; 
}


/* =============== 顶栏 =============== */
#top-bar {
    box-shadow: none !important; 
}
#top-settings-holder {
    background-color: rgb(253, 245, 246); 
}
#top-settings-holder .drawer-toggle .drawer-icon {
    background: rgb(253, 245, 246) !important;
    color: var(--dusty-rose) !important;
    font-size: 1.55em !important; 
    display: inline-flex;
    align-items: center;
    justify-content: center;
}


/* =============== 底栏 =============== */
#form_sheld {
    position: static !important;
    left: 0;
    right: 0;
    width: 100% !important;
    background: transparent !important;
    border: none !important;
    z-index: auto !important;
    display: flex;
    justify-content: center;
    pointer-events: auto !important;
    padding: 0 0 10px 0 !important;
}
#form_sheld #send_form {
    border-radius: 15px !important;  
    background: linear-gradient(180deg, #FFFFFF 20%, var(--ballet-pink-light) 100%) !important;
    border: 1px solid var(--ballet-pink) !important;
    border-bottom-width: 1px !important;   
    width: 96%;
    pointer-events: auto;
    padding: 6px 10px 10px 10px !important;
    box-shadow: 
        inset 0 1px 0 #FFF, 
        0 4px 0 var(--ballet-pink), 
        0 8px 15px rgba(229, 197, 203, 0.35) !important;        
    transition: all 0.3s cubic-bezier(0.25, 0.8, 0.25, 1);
}
#form_sheld #send_form:hover {
    transform: translateY(-2px);
    box-shadow: 
        inset 0 1px 0 #FFF,
        0 5px 0 var(--shen-ballet),
        0 12px 20px rgba(229, 197, 203, 0.45) !important;
}

#send_textarea {
    background: linear-gradient(180deg, #FFFFFF 20%, var(--ballet-pink-light) 100%) !important;
    border: 1px solid rgba(229, 197, 203, 0.3) !important;
    border-radius: 10px !important;   
    color: var(--text-color) !important;
    box-shadow: inset 0 2px 5px rgba(110, 92, 100, 0.06) !important;       
    padding: 8px 4px !important;
    clip-path: none !important;
    background-color: transparent !important;
    border-color: transparent !important;
}
#send_textarea:focus {
    background: linear-gradient(180deg, #FFFFFF 20%, var(--ballet-pink-light) 100%) !important;
    border-color: var(--ballet-pink) !important;
    box-shadow: inset 0 2px 4px rgba(229, 197, 203, 0.15) !important;
}

#options_button::before, 
#extensionsMenuButton::before, 
#send_but::before, 
#mes_stop::before {
    content: '' !important;
    display: none !important; 
}
#extensionsMenuButton,
#options_button {
    background: url('https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMcaBpOWHawhlHOgUordxq5k8K64uVvAACHx4AApKD0FVHDAABlzCOm_I2BA.png') no-repeat center center !important;
    background-size: contain !important;
    width: 30px !important;
    height: 30px !important;
    margin-top: 5px !important;
    opacity: 0.8;
}
#send_but { 
    background: url('https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEDcHto8JPKpVo5gCDNtmtCdfaU6Y4yeQAC7RwAAqpXgVdcGk8w2C7CsDYE.png') no-repeat center center !important;
    background-size: contain !important;
    width: 35px !important;
    height: 35px !important;
    opacity: 0.9;
}
#send_form #mes_stop {
    background: url('https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMfWtpOqfJomes3DV7F1uMUb4zN5e18gAC4yAAAm312FXclZ4FpsNnKDYE.png') no-repeat center center !important;
    background-size: contain !important;
    width: 35px !important;
    height: 35px !important;
    border: none !important;
    box-shadow: none !important;
    font-size: 0 !important;
    color: transparent !important;
    opacity: 0.9;
}
#extensionsMenuButton:hover,
#options_button:hover,
#send_but:hover,
#send_form #mes_stop:hover {
    opacity: 1;
    filter: drop-shadow(0 2px 3px rgba(229, 197, 203, 0.4));
    transform: scale(1.05);
}

/* 输入框提示文字,感谢墨千尾老师 */
#send_textarea::placeholder {
color: transparent;
opacity: 0;
}
#nonQRFormItems {
position: relative !important;
}
#nonQRFormItems::after {
content: "⋅ ˚ ₊ 𓏵‧𐙚𝐵𝑎𝑙𝑙𝑒𝑡 ‧₊˚ ⋅。";
position: absolute;
top: 55%;
left: 50%;
transform: translate(-50%, -50%);
color: var(--shen-ballet) !important;
font-size: 0.55em;
pointer-events: none;
white-space: nowrap;
z-index: 1;
}
#send_textarea:not(:placeholder-shown) ~ * #nonQRFormItems::after,
#nonQRFormItems:has(#send_textarea:not(:placeholder-shown))::after {
display: none;
}


/* =============== QR =============== */
.qr--button, 
.qr--button .qr--button-label {
    color: var(--text-blue) !important; 
}

/* 隐藏QR，感谢十二老师 */
.qr--buttons {
  opacity: 0;
  visibility: hidden;
  max-height: 0;
  transform: translateY(20px);
  pointer-events: none;
  transition: opacity 0.3s ease-in-out, visibility 0.3s ease-in-out, max-height 0.5s ease, transform 0.5s ease;
}
#send_form:focus-within .qr--buttons {
  opacity: 1;
  visibility: visible;
  max-height: 100px; 
  transform: translateY(0);
  pointer-events: auto;
}


/* =============== 聊天界面 =============== */
#chat {
    -webkit-backdrop-filter: none !important;
}
.mes {
    display: flex;
    flex-direction: column;
    align-items: center;
    margin-bottom: 45px;
    position: relative;
    overflow: visible !important;
}

/* 聊天气泡 */
.mes .mes_block {
    width: 95%;
    max-width: 720px;
    background: linear-gradient(180deg, #FFF9FA, #FFFFFF);
    color: var(--text-color) !important;
    border-radius: 20px;
    border: 1px solid rgba(229, 197, 203, 0.6);
    box-shadow: 0 6px 14px rgba(230, 200, 205, 0.25) !important;
    overflow: visible !important;
    padding: 10px 12px 15px 12px !important;     
    min-height: 120px;
    display: flex !important;
    flex-direction: column !important; 
    justify-content: flex-start !important; 
    box-sizing: border-box;
    transform: none !important;
    position: relative !important; 
}

/* 聊天正文区域 */
.mes .mes_text {
    padding: 20px 0; 
    text-align: justify;
    text-justify: inter-character;
    line-height: 1.55;
}
.mes .mes_text p:first-child { margin-top: 0; }
.mes .mes_text p:last-child { margin-bottom: 0; }

/* 编辑按钮 */
.mes .mes_buttons {
    position: absolute; 
    top: 20px;
    right: 30px;
    color: var(--shen-rose);
    z-index: 4;
}

/* 外层包裹容器 */
.mes .mesAvatarWrapper {
    display: flex;
    flex-wrap: wrap; 
    justify-content: center; 
    align-items: center; 
    width: 100%;
    padding: 10px 0px 8px; 
    gap: 5px 10px; 
}

/* 姓名和时间戳 */
.mes .ch_name {
    position: relative !important;
    left: auto !important;
    top: auto !important;    
    width: 100%;
    margin: 0 auto 5px auto !important;
    padding: 0;   
    background-color: transparent;
    display: flex;
    flex-direction: column;
    align-items: center !important;
    gap: 2px;
    z-index: 5;
}
/* 姓名样式 */
.mes .name_text {
    font-size: 1.2em;
    font-weight: bold;
    color: #6E5C64;
}
/* 时间戳样式 */
.mes .timestamp {
    font-size: 0.8em;
    color: #6E5C64;
}
/* 楼层、计时、Token数 */
.mes .mesIDDisplay,
.mes .mes_timer,
.mes .tokenCounterDisplay {
    font-size: 0.8em;
    color: #6E5C64;
    background-color: transparent;
    padding: 5px 0;
}
.mes .mes_timer:empty,
.mes .mesIDDisplay:empty,
