}


/* ============= 代码块和各种文本 ============= */
.mes pre,
.mes pre[class*="language-"] {
    background-color: #FAFCFF !important;
    border: 1px solid #FFFFFF !important;
    border-radius: 10px !important;
    margin: 10px 0 !important;
    box-shadow: 
        inset 2px 2px 6px rgba(110, 92, 100, 0.08), 
        inset -2px -2px 6px rgba(255, 255, 255, 0.8),
        0 1px 2px rgba(0,0,0,0.05) !important;
}
.mes pre code {
    color: var(--text-color) !important;
    font-family: var(--font-main) !important; 
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    padding: 15px 20px !important;   
}

/* 说明文本中的代码块 */
code, kbd, .markdown-content code {
    background-color: #FFFDFE !important;
    border: 1px solid rgba(229, 197, 203, 0.8) !important; 
    color: var(--text-color) !important;
    border-radius: 4px !important;
    padding: 1px 4px !important; 
    font-family: monospace !important;
}

/* 行内代码 */
.mes :not(pre) > code {
    background: linear-gradient(180deg, rgba(255,255,255,0.15), transparent) var(--shen-ballet) !important;    
    color: #FFF !important;
    font-family: var(--font-main) !important;
    text-shadow: 0 1px 1px rgba(166, 124, 82, 0.2);   
    border: none !important;
    border-radius: 6px !important; 
    padding: 2px 5px !important;
    box-shadow: 
        inset 0 1.5px 0 rgba(255, 255, 255, 0.5), 
        inset 0 -1.5px 0 rgba(0, 0, 0, 0.1),
        0 2px 4px rgba(229, 197, 203, 0.4) !important;
    border: 1px solid rgba(255, 255, 255, 0.2) !important;
}

/* 引用块 */
.mes blockquote {
    position: relative;
    background: linear-gradient(180deg, var(--ballet-pink-light) 0%, #FFFFFF 100%) !important;
    border: 1px solid var(--ballet-pink) !important;
