    padding: 12px 18px 12px 12px !important; 
    margin: 16px 0;
    box-shadow: 
        inset 0 0 10px rgba(255, 255, 255, 0.8),
        0 2px 8px rgba(229, 197, 203, 0.3) !important;        
    overflow: visible !important; 
}
