    content: '';
    position: absolute;
    top: -4px;
    bottom: -1px;
    right: -10px; 
    width: 20px;  
    background-image: url('https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEMgZJpO3ISvBlfejUL28RdW8IF8PmehwACPRkAAm314FXlU_QaQSYJnDYE.png');
