/* =============== 加载动画 =============== */
#preloader {
    position: fixed;
    margin: 0;
    padding: 0;
    top: 0;
    left: 0;
    z-index: 999999;
    width: 100vw;
    height: 100vh;
    background-color: #FFFFFF; 
    opacity: 1;
}
#load-spinner {
--spinner-size: 120px; 
transition: all var(--animation-duration-2x) ease-out;
opacity: 1;
top: calc(50% - var(--spinner-size) / 2);
left: calc(50% - var(--spinner-size) / 2);
position: absolute;
width: var(--spinner-size);
height: var(--spinner-size);
background-image: url(https://img.remit.ee/api/file/BQACAgUAAyEGAASHRsPbAAEDZxNo7zJ4h1nO70VeToxCpacFgn3r0wACNxsAAvwJeVfNBD4bsCasETYE.png);
background-size: contain;
background-repeat: no-repeat;
background-position: center;
filter: drop-shadow(0 3px 6px rgba(255, 255, 255, 0.1));
animation: danceJump 1.2s ease-in-out infinite;
}
#load-spinner::before { display: none !important; }
@keyframes danceJump {
    0%, 100% { transform: translateY(0) scale(1); } 
    50% { transform: translateY(-15px) scale(1.05); } 
}
